import React,{useState} from 'react';
import AddPost from './AddPost';
import './App.css';
import Post from './component/Post';


function App() {
const [counter, setCounter] = useState(0)
const [posts, setPosts] = useState([{title:"new post!",info:"hey"} , {title:"new cat",info:"i got a new cat and calles him Boris"},{title:"its my brithday",info:"celebratin with friends today at 10 pm "},{title:"won in a game",info:"Bal bla bla bla "}])
const addNewPost= (title,info)=>{
  setPosts([{title:title ,info:info},...posts])
}


  return (
    <div className="App">
      <div className="App">
        <h1>Let's count together!</h1>
        <div>{counter}</div>
        <button onClick={()=> {setCounter(counter+1)}}>+</button>
        <button onClick={()=> {setCounter(counter-1)}}>-</button>

      <AddPost newPost={addNewPost}/>
      {posts.map((item)=>{
        return <Post title={item.title} info={item.info}/>})}
      </div>
    </div>
  );
}

export default App;
